"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[23130],{71971:e=>{e.exports=JSON.parse('{"tag":{"label":"harvesting","permalink":"/dst-api-webdocs/docs/tags/harvesting","allTagsPath":"/dst-api-webdocs/docs/tags","count":9,"items":[{"id":"game-scripts/prefabs/beebox","title":"Beebox","description":"Manages a beehive-like structure that produces honey over time and spawns bees when harvested, with state changes based on light, season, and player actions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beebox"},{"id":"game-scripts/prefabs/cave_banana_tree","title":"Cave Banana Tree","description":"Manages the full lifecycle of a cave banana tree, including growth, harvesting, chopping, burning, and regrowth into stumps or burnt stumps.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cave_banana_tree"},{"id":"game-scripts/behaviours/controlminions","title":"Controlminions","description":"Controls minion behavior to harvest, pick, or pick up nearby target entities within a defined radius.","permalink":"/dst-api-webdocs/docs/game-scripts/behaviours/controlminions"},{"id":"game-scripts/components/harvestable","title":"Harvestable","description":"Manages plant-like entities that grow over time and can be harvested to yield items, handling growth progress, pausing, and item dropping.","permalink":"/dst-api-webdocs/docs/game-scripts/components/harvestable"},{"id":"game-scripts/prefabs/marbleshrub","title":"Marbleshrub","description":"Manages the growth, mining, and loot generation of marble shrubs, which are mutable ground structures that progress through growth stages and yield marble resources when mined.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/marbleshrub"},{"id":"game-scripts/prefabs/plant_normal","title":"Plant Normal","description":"Implements lifecycle and interaction logic for growing crops and their ground variants, including maturation, withering, harvesting, burning, and rotting behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/plant_normal"},{"id":"game-scripts/components/regrowthmanager","title":"Regrowthmanager","description":"Manages the scheduled regrowth of harvestable plants and structures after they are collected, using time-based timers and world state conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/regrowthmanager"},{"id":"game-scripts/prefabs/sapling","title":"Sapling","description":"Manages the lifecycle, interaction, and transformation of sapling entities, including growth, harvesting, transplanting, and optional moon-phase conversion for seasonal variants.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/sapling"},{"id":"game-scripts/prefabs/singingshell","title":"Singingshell","description":"A musical harvesting component that cycles through musical notes, tending nearby plants when activated, and dropping loot upon being hammered.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/singingshell"}],"unlisted":false}}')}}]);